--
-- Table structure for table `billings`
--

DROP TABLE IF EXISTS `billings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `billings` (
  `billing_id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `lease_id` bigint unsigned NOT NULL,
  `billing_type` enum('monthly','move_in','move_out') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'monthly',
  `billing_date` date NOT NULL,
  `next_billing` date NOT NULL,
  `due_date` date DEFAULT NULL,
  `to_pay` decimal(8,2) NOT NULL,
  `amount` decimal(8,2) NOT NULL,
  `previous_balance` decimal(10,2) NOT NULL DEFAULT '0.00',
  `status` enum('Unpaid','Overdue','Paid') COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`billing_id`),
  KEY `billings_lease_id_foreign` (`lease_id`),
  CONSTRAINT `billings_lease_id_foreign` FOREIGN KEY (`lease_id`) REFERENCES `leases` (`lease_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=157 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

