DROP TABLE IF EXISTS `maintenance_feedback`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `maintenance_feedback` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `request_id` bigint unsigned NOT NULL,
  `tenant_id` bigint unsigned NOT NULL,
  `rating` tinyint NOT NULL,
  `experience_tag` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `comment` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `maintenance_feedback_request_id_tenant_id_unique` (`request_id`,`tenant_id`),
  KEY `maintenance_feedback_tenant_id_foreign` (`tenant_id`),
  CONSTRAINT `maintenance_feedback_request_id_foreign` FOREIGN KEY (`request_id`) REFERENCES `maintenance_requests` (`request_id`) ON DELETE CASCADE,
  CONSTRAINT `maintenance_feedback_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
