--
-- Table structure for table `units`
--

DROP TABLE IF EXISTS `units`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `units` (
  `unit_id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `property_id` bigint unsigned NOT NULL,
  `manager_id` bigint unsigned DEFAULT NULL,
  `floor_number` int NOT NULL,
  `unit_number` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `occupants` enum('Male','Female','Co-ed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Co-ed',
  `bed_type` enum('Single','Bunk','Twin') COLLATE utf8mb4_unicode_ci NOT NULL,
  `room_type` enum('Standard','Deluxe','Suite') COLLATE utf8mb4_unicode_ci NOT NULL,
  `room_cap` int NOT NULL,
  `unit_cap` int NOT NULL,
  `price` decimal(8,2) NOT NULL,
  `amenities` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`unit_id`),
  KEY `units_property_id_foreign` (`property_id`),
  KEY `units_manager_id_foreign` (`manager_id`),
  CONSTRAINT `units_manager_id_foreign` FOREIGN KEY (`manager_id`) REFERENCES `users` (`user_id`) ON DELETE SET NULL,
  CONSTRAINT `units_property_id_foreign` FOREIGN KEY (`property_id`) REFERENCES `properties` (`property_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=121 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

