DROP TABLE IF EXISTS `utility_bills`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `utility_bills` (
  `utility_bill_id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `unit_id` bigint unsigned NOT NULL,
  `utility_type` enum('electricity','water') COLLATE utf8mb4_unicode_ci NOT NULL,
  `billing_period` date NOT NULL,
  `total_amount` decimal(10,2) NOT NULL,
  `tenant_count` int unsigned NOT NULL,
  `per_tenant_amount` decimal(10,2) NOT NULL,
  `entered_by` bigint unsigned NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`utility_bill_id`),
  KEY `utility_bills_unit_id_foreign` (`unit_id`),
  KEY `utility_bills_entered_by_foreign` (`entered_by`),
  CONSTRAINT `utility_bills_entered_by_foreign` FOREIGN KEY (`entered_by`) REFERENCES `users` (`user_id`) ON DELETE CASCADE,
  CONSTRAINT `utility_bills_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `units` (`unit_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=179 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

